C++<pre><code>#include&lt;stdio.h&gt;
#include&lt;stdlib.h&gt;
typedef struct Node
{
    int data;
    struct Node* next;
}Node;
int isEmpty(Node* top)
{
    return (top==NULL);
}
void push(Node** top,int value)
{
    Node* newnode=(Node*)malloc(sizeof(Node));
    newnode-&gt;data=value;
    newnode-&gt;next=*top;
    *top=newnode;
}
void pop(Node** top)
{
    if(isEmpty(*top)) return ;
    Node* temp=*top;
    *top=temp-&gt;next;
    free(temp);
}
void peek(Node* top)
{
    if(isEmpty(top)) printf("Stack is empty\n");
    else printf("Top element is: %d\n",top-&gt;data);
}
void display(Node* top)
{
    if(isEmpty(top)) printf("Stack is empty\n");
    Node* temp=top;
    printf("Stack elements:\n");
    while(temp!=NULL)
    {
        printf("%d ",temp-&gt;data);
        temp=temp-&gt;next;
    }
    printf("\n");
}
int main()
{
    return 0;
}
</code></pre>

C++<pre><code>#include&lt;stdio.h&gt;
#include&lt;stdlib.h&gt;
typedef struct Node
{
    int data;
    struct Node* prev;
    struct Node* next;
}Node;
void displayForward(Node* head)
{
    Node* temp=head;
    while(temp!=NULL)
    {
        printf("%d",temp-&gt;data);
        if(temp-&gt;next!=NULL) printf(" &lt;-&gt; ");
        temp=temp-&gt;next;
    }
    printf(" -&gt; NULL\n");
}
void displayBackward(Node* tail)
{
    Node* temp=tail;
    while(temp!=NULL)
    {
        printf("%d",temp-&gt;data);
        if(temp-&gt;prev!=NULL) printf(" &lt;-&gt; ");
        temp=temp-&gt;prev;
    }
    printf(" -&gt; NULL\n");
}
void insertAtBeginning(Node** head,Node** tail,int value)
{
    Node* newnode=(Node*)malloc(sizeof(Node));
    newnode-&gt;data=value;
    newnode-&gt;prev=NULL;
    newnode-&gt;next=*head;
    if(*head==NULL)
    {
        *head=*tail=newnode;
    }
    else
    {
        (*head)-&gt;prev=newnode;
        *head=newnode;
    }
}
void insertAtEnd(Node** head,Node** tail,int value)
{
    Node* newnode=(Node*)malloc(sizeof(Node));
    newnode-&gt;data=value;
    newnode-&gt;next=NULL;
    newnode-&gt;prev=*tail;
    if(*tail==NULL)
    {
        *head=*tail=newnode;
    }
    else
    {
        (*tail)-&gt;next=newnode;
        *tail=newnode;
    }
}
void insertAtPosition(Node** head,Node** tail,int value,int position)
{
    if(position==1)
    {
        insertAtBeginning(head,tail,value);
        return ;
    }
    Node* newnode=(Node*)malloc(sizeof(Node));
    newnode-&gt;data=value;
    Node* temp=*head;
    for(int i=1;i&lt;position-1&amp;&amp;temp!=NULL;i++)
    {
        temp=temp-&gt;next;
    }
    if(temp==NULL)
    {
        printf("Position out of range\n");
        free(newnode);
        return ;
    }
    newnode-&gt;next=temp-&gt;next;
    newnode-&gt;prev=temp;
    if(temp-&gt;next!=NULL)
    {
        temp-&gt;next-&gt;prev=newnode;
    }
    else *tail=newnode;
    temp-&gt;next=newnode;
}
void deleteAtBeginning(Node** head,Node** tail)
{
    if(*head==NULL) return ;
    Node* temp=*head;
    *head=temp-&gt;next;
    if(*head!=NULL)
    {
        (*head)-&gt;prev=NULL;
    }
    else *tail=NULL;
    free(temp);
}
void deleteAtEnd(Node** head,Node** tail)
{
    if(*head==NULL) return ;
    Node* temp=*tail;
    *tail=temp-&gt;prev;
    if(*tail!=NULL)
    {
        (*tail)-&gt;next=NULL;
    }
    else *head=NULL;
    free(temp);
}
void deleteAtPosition(Node** head,Node** tail,int position)
{
    if(*head==NULL||position&lt;1) return ;
    Node* temp=*head;
    int index=1;
    while(temp!=NULL&amp;&amp;index&lt;position)
    {
        temp=temp-&gt;next;
        index++;
    }
    if(temp==NULL)
    {
        printf("Position out of range\n");
        return ;
    }
    if(temp-&gt;prev!=NULL)
    {
        temp-&gt;prev-&gt;next=temp-&gt;next;
    }
    else *head=temp-&gt;next;
    if(temp-&gt;next!=NULL)
    {
        temp-&gt;next-&gt;prev=temp-&gt;prev;
    }
    else *tail=temp-&gt;prev;
    free(temp);
}
int main()
{
    Node* head=NULL;
    Node* tail=NULL;
    insertAtBeginning(&amp;head,&amp;tail,70);
    insertAtBeginning(&amp;head,&amp;tail,80);
    insertAtBeginning(&amp;head,&amp;tail,90);
    printf("Initial list (forward) : ");
    displayForward(head);
    printf("Initial list (backward) : ");
    displayBackward(tail);
    insertAtBeginning(&amp;head,&amp;tail,100);
    printf("\nAfter inserting 100 at front: ");
    displayForward(head);
    insertAtEnd(&amp;head,&amp;tail,200);
    printf("After inserting 200 at at end: ");
    displayForward(head);
    printf("\nAfter inserting 555 at position 4: ");
    insertAtPosition(&amp;head,&amp;tail,555,4);
    displayForward(head);
    deleteAtBeginning(&amp;head,&amp;tail);
    printf("After deleting front: ");
    displayForward(head);
    deleteAtEnd(&amp;head,&amp;tail);
    printf("After deleting end: ");
    displayForward(head);
    deleteAtPosition(&amp;head,&amp;tail,3);
    printf("After deleting position 3: ");
    displayForward(head);
    return 0;
}
</code></pre>

C++<pre><code>#include&lt;stdio.h&gt;
#include&lt;stdlib.h&gt;
typedef struct Node
{
    int data;
    struct Node* next;
}Node;
void insertAtBeginning(Node** head,int value)
{
    Node* newnode=(Node*)malloc(sizeof(Node));
    newnode-&gt;data=value;
    newnode-&gt;next=*head;
    *head=newnode;
}
void insertAtEnd(Node** head,int value)
{
    Node* newnode=(Node*)malloc(sizeof(Node));
    newnode-&gt;data=value;
    newnode-&gt;next=NULL;
    if(*head==NULL)
    {
        *head=newnode;
        return ;
    }
    Node* temp=*head;
    while(temp-&gt;next!=NULL)
    {
        temp=temp-&gt;next;
    }
    temp-&gt;next=newnode;
}
void insertAtPosition(Node** head,int value,int position)
{
    if(position==1)
    {
        insertAtBeginning(head,value);
        return ;
    }
    Node* newnode=(Node*)malloc(sizeof(Node));
    newnode-&gt;data=value;
    Node* temp=*head;
    for(int i=1;i&lt;position-1&amp;&amp;temp!=NULL;i++)
    {
        temp=temp-&gt;next;
    }
    if(temp==NULL)
    {
        printf("Position out of range\n");
        free(newnode);
        return ;
    }
    newnode-&gt;next=temp-&gt;next;
    temp-&gt;next=newnode;
}
void deleteAtBeginning(Node** head)
{
    if(*head==NULL) return ;
    Node* temp=*head;
    *head=temp-&gt;next;
    free(temp);
    return ;
}
void deleteAtEnd(Node** head)
{
    if(*head==NULL) return ;
    Node* temp=*head;
    if(temp-&gt;next==NULL)
    {
        *head=NULL;
        free(temp);
        return ;
    }
    Node* prev=NULL;
    while(temp-&gt;next!=NULL)
    {
        prev=temp;
        temp=temp-&gt;next;
    }
    prev-&gt;next=NULL;
    free(temp);
}
void deleteAtPosition(Node** head,int position)
{
    if(*head==NULL) return ;
    Node* temp=*head;
    if(position==1)
    {
        deleteAtBeginning(head);
        return ;
    }
    Node* prev=NULL;
    for(int i=1;i&lt;position&amp;&amp;temp!=NULL;i++)
    {
        prev=temp;
        temp=temp-&gt;next;
    }
    if(temp==NULL)
    {
        printf("Position out of range\n");
        return ;
    }
    prev-&gt;next=temp-&gt;next;
    free(temp);
}
void printList(Node* head)
{
    if(head==NULL)
    {
        printf("The list is empty!\n");
        return ;
    }
    Node* temp=head;
    printf("\nThe linked list: \n");
    while(temp!=NULL)
    {
        printf("%d -&gt; ",temp-&gt;data);
        temp=temp-&gt;next;
    }
    printf("NULL\n");
}
int search(Node* head,int value)
{
    Node* temp=head;
    int position=1;
    while(temp!=NULL)
    {
        if(temp-&gt;data==value) return position;
        temp=temp-&gt;next;
        position++;
    }
    return -1;
}
int main()
{
    Node* head=NULL;
    insertAtBeginning(&amp;head,10);
    insertAtBeginning(&amp;head,5);
    insertAtEnd(&amp;head,20);
    insertAtEnd(&amp;head,30);
    insertAtPosition(&amp;head,25,4);
    printList(head);
    printf("\nPosition of 25: %d\n",search(head, 25));
    deleteAtBeginning(&amp;head);
    printf("\nAfter deleting beginning: ");
    printList(head);
    deleteAtEnd(&amp;head);
    printf("\nAfter deleting end: ");
    printList(head);
    deleteAtPosition(&amp;head,2);
    printf("\nAfter deleting position 2: ");
    printList(head);
    return 0;
}
</code></pre>

C++<pre><code>#include&lt;bits/stdc++.h&gt;
#define Maxn 80
using namespace std;
typedef __int128 ll;
ll a[Maxn+5][Maxn+5],dp[Maxn+5][Maxn+5];
ll read()
{
    ll x=0;
    char c=' ';
    while(c&lt;'0'||c&gt;'9') c=getchar();
    while(c&gt;='0'&amp;&amp;c&lt;='9')
    {
        x=x*10+c-'0';
        c=getchar();
    }
    return x;
}
void print(ll x)
{
    if(x&gt;10) print(x/10);
    putchar('0'+x%10);
}
int main()
{
    int n,m;
    scanf("%d%d",&amp;n,&amp;m);
    for(int i=0;i&lt;n;i++)
    {
        for(int j=0;j&lt;m;j++)
        {
            a[i][j]=read();
        }
    }
    ll ans=0;
    for(int r=0;r&lt;n;r++)
    {
        for(int i=0;i&lt;m;i++) dp[i][i]=a[r][i]&lt;&lt;1;
        for(int len=2;len&lt;=m;len++)
        {
            for(int i=0;i&lt;m;i++)
            {
                int j=i+len-1;
                dp[i][j]=max((a[r][i]&lt;&lt;1)+(dp[i+1][j]&lt;&lt;1),(a[r][j]&lt;&lt;1)+(dp[i][j-1]&lt;&lt;1));
            }
        }
        ans+=dp[0][m-1];
    }
    print(ans);
}
</code></pre>

C++<pre><code>#include&lt;bits/stdc++.h&gt;
#define Maxn 100000
using namespace std;
int a[Maxn+5],d[Maxn+5],p[Maxn+5],pre[Maxn+5];
vector&lt;int&gt; ans;
int main()
{
    int n;
    scanf("%d",&amp;n);
    for(int i=0;i&lt;n;i++) scanf("%d",a+i);
    int k=0;
    for(int i=0;i&lt;n;i++)
    {
        int tmp=upper_bound(d,d+k,a[i])-d; //最长不下降子序列
        // int tmp=lower_bound(d,d+k,a[i])-d; 最长上升子序列
        pre[i]=tmp?p[tmp-1]:-1;
        d[tmp]=a[i];
        p[tmp]=i;
        if(tmp==k) k++;
    }
    for(int i=p[k-1];i!=-1;i=pre[i]) ans.push_back(a[i]);
    printf("%d\n",ans.size());
    for(int i=ans.size()-1;i&gt;=0;i--) printf("%d ",ans[i]);
    return 0;
}
