C++<pre><code>// 找最小的n，使得n阶乘末尾有k个0
#include&lt;bits/stdc++.h&gt;
#define Maxn 1000
using namespace std;
int get(int x)
{
    int ans=0;
    while(x)
    {
        ans+=x/5;
        x/=5;
    }
    return ans;
}
int main()
{
    int k;
    scanf("%d",&amp;k);
    int l=1,r=10000000,best=-1;
    while(l&lt;=r)
    {
        int mid=(l+r)&gt;&gt;1;
        if(get(mid)&gt;=k)
        {
            best=mid;
            r=mid-1;
        }
        else l=mid+1;
    }
    printf("%d",best);
    return 0;
}
