{
    for(int i=1;i&lt;31;i++)
    {
        f[i][x]=f[i-1][f[i-1][x]];
        c[i][x]=c[i-1][f[i-1][x]]+c[i-1][x];
    }
    for(int i=head[x];i!=-1;i=nex[i])
    {
        if(to[i]==fa) continue;
        f[0][to[i]]=x;
        c[0][to[i]]=w[i];
        dep[to[i]]=dep[x]+1;
        dfs(to[i],x);
    }
}
pair&lt;int,int&gt; lca(int x,int y)
{
    if(dep[x]&gt;dep[y]) swap(x,y);
    int tmp=dep[y]-dep[x];
    int cnt=0,ans=0;
    while(tmp)
    {
        if(tmp&amp;1)
        {
            ans+=c[cnt][y];
            y=f[cnt][y];
        }
        tmp&gt;&gt;=1;
        cnt++;
    }
    if(x==y) return make_pair(x,ans);
