    dfs1(root,0);
    dfs2(root,root);
    for(int i=1;i&lt;=n;i++) a[i]=arr[rnk[i]]%Mod;
    build(1,1,n);
    for(int i=1;i&lt;=m;i++)
    {
        int op;
