            ll sum=0;
            while(top[x]!=top[y])
            {
                if(dep[top[x]]&lt;dep[top[y]]) swap(x,y);
                sum=(sum+query(1,dfn[top[x]],dfn[x]))%Mod;
                x=fa[top[x]];
            }
            if(dep[x]&gt;dep[y]) swap(x,y);
            sum=(sum+query(1,dfn[x],dfn[y]))%Mod;
            printf("%lld\n",sum);
        }
        else if(op==3)
        {
            int x;
