            update(1,dfn[x],dfn[x]+siz[x]-1,z);
        }
        else
        {
            int x;
            scanf("%d",&amp;x);
            printf("%lld\n",query(1,dfn[x],dfn[x]+siz[x]-1));
        }
    }
