    if(dp[num][pos]!=-1) return dp[num][pos];
    int res=0;
    for(int i=0;i&lt;10;i++) res+=dfs(pos-1,i);
    if(num==6) res-=dfs(pos-1,2);
    if(num==4) return dp[num][pos]=0;
    return dp[num][pos]=res;
}
