    int cnt=0;
    while(x)
    {
        a[cnt++]=x%10;
        x/=10;
    }
    int ans=1;
    bool flag=false;
    for(int i=cnt-1;i&gt;=0;i--)
    {
        for(int j=0;j&lt;a[i];j++) ans+=dfs(i,j);
        if(flag&amp;&amp;a[i]&gt;2) ans-=dfs(i,2);
