                a[j][k]-=a[j][i]*a[i][k];
            }
        }
    }
    for(int i=n-1;i&gt;=1;i--)
    {
        for(int j=i+1;j&lt;=n;j++)
        {
            a[i][n+1]-=a[i][j]*a[j][n+1];
        }
    }
    return 1;
}
