C++<pre><code>#include&lt;bits/stdc++.h&gt;
#define Maxn 100000
using namespace std;
typedef long long ll;
struct node
{
    int l,r;
    ll sum,lazy;
}tr[Maxn&lt;&lt;2];
ll a[Maxn+5];
void pushup(int p)
{
    tr[p].sum=tr[p&lt;&lt;1].sum+tr[p&lt;&lt;1|1].sum;
}
void pushdown(int p)
{
    if(tr[p].lazy)
    {
        ll k=tr[p].lazy;
        tr[p&lt;&lt;1].sum+=(tr[p&lt;&lt;1].r-tr[p&lt;&lt;1].l+1)*k;
        tr[p&lt;&lt;1|1].sum+=(tr[p&lt;&lt;1|1].r-tr[p&lt;&lt;1|1].l+1)*k;
        tr[p&lt;&lt;1].lazy+=k;
        tr[p&lt;&lt;1|1].lazy+=k;
        tr[p].lazy=0;
    }
}
void build(int p,int l,int r)
{
    tr[p]={l,r,a[l],0};
    if(l==r) return ;
    int mid=(l+r)&gt;&gt;1;
    build(p&lt;&lt;1,l,mid);
    build(p&lt;&lt;1|1,mid+1,r);
    pushup(p);
}
ll query(int p,int x,int y)
{
    if(x&lt;=tr[p].l&amp;&amp;tr[p].r&lt;=y) return tr[p].sum;
    int mid=(tr[p].l+tr[p].r)&gt;&gt;1;
    ll sum=0;
    pushdown(p);
    if(x&lt;=mid) sum+=query(p&lt;&lt;1,x,y);
    if(y&gt;mid) sum+=query(p&lt;&lt;1|1,x,y);
    return sum;
}
void modify(int p,int x,int y,ll k)
{
    if(x&lt;=tr[p].l&amp;&amp;tr[p].r&lt;=y)
    {
        tr[p].sum+=(tr[p].r-tr[p].l+1)*k;
        tr[p].lazy+=k;
        return ;
    }
    int mid=(tr[p].l+tr[p].r)&gt;&gt;1;
    pushdown(p);
    if(x&lt;=mid) modify(p&lt;&lt;1,x,y,k);
    if(y&gt;mid) modify(p&lt;&lt;1|1,x,y,k);
    pushup(p);
}
int main()
{
    int n,m;
    scanf("%d%d",&amp;n,&amp;m);
    for(int i=1;i&lt;=n;i++) scanf("%lld",a+i);
    build(1,1,n);
    while(m--)
    {
        int op;
        scanf("%d",&amp;op);
        if(op==1)
        {
            int x,y;
            ll k;
            scanf("%d%d%lld",&amp;x,&amp;y,&amp;k);
            modify(1,x,y,k);
        }
