    init();
    for(int i=1;i&lt;=n;i++)
    {
        int x;
        scanf("%d",&amp;x);
        add(x,i);
        t[i]=x;
    }
    for(int i=1;i&lt;=n;i++) scanf("%lld",a+i);
    for(int i=1;i&lt;=n;i++) dir[i]=a[t[i]]&gt;a[i]?1:-1;
    for(int i=1;i&lt;=n;i++)
    {
        if(!vis[i])
        {
            mn=INF;
            flag=false;
            dfs1(i,i);
            if(mn!=INF)
            {
                ans[root]=mn;
                dfs2(root,edge);
            }
        }
