C++<pre><code>#include&lt;bits/stdc++.h&gt;
#define Maxn 100000
using namespace std;
int t,L,k,n;
int s[Maxn*2+5];
struct node
{
    int x,y;
}p[Maxn+5];
int nx[21][Maxn*2+5];
auto bel(int x,int y)
{
    if(y==0) return 1;
    else if(x==L) return 2;
    else if(y==L) return 3;
    else return 4;
}
int cmp(node x,node y)
{
    auto a=bel(x.x,x.y),b=bel(y.x,y.y);
    if(a!=b) return a&lt;b;
    else if(a==1) return x.x&lt;y.x;
    else if(a==2) return x.y&lt;y.y;
    else if(a==3) return y.x&lt;x.x;
    else return y.y&lt;x.y;
}
int nxt(int x,int step)
{
    int t=0;
    while(step)
    {
        if(step&amp;1) x=nx[t][x];
        t++;
        step&gt;&gt;=1;
    }
    return x;
}
bool check(int x)
{
    for(int i=1;i&lt;=n*2;i++)
    {
        int l=i,r=n*2,best=-1;
        while(l&lt;=r)
        {
            int mid=(l+r)&gt;&gt;1;
            if(s[mid]-s[i]&gt;=x)
            {
                best=mid;
                r=mid-1;
            }
            else l=mid+1;
        }
        nx[0][i]=(best==-1?n*2:best);
    }
    for(int i=1;i&lt;=20;i++)
    {
        for(int j=1;j&lt;=n*2;j++)
        {
            nx[i][j]=nx[i-1][nx[i-1][j]];
        }
    }
    for(int i=1;i&lt;=n;i++)
    {
        if(s[i+n]-s[nxt(i,k-1)]&gt;=x) return true;
    }
    return false;
}
int main()
{
    ios::sync_with_stdio(false);
    cin.tie(0);
    cin&gt;&gt;t;
    while(t--)
    {
        cin&gt;&gt;L&gt;&gt;k&gt;&gt;n;
        for(int i=1;i&lt;=n;i++)
        {
            int x,y;
            cin&gt;&gt;x&gt;&gt;y;
            p[i]={x,y};
        }
        sort(p+1,p+1+n,cmp);
        for(int i=1;i&lt;=n;i++)
        {
            if(p[i].y==0) s[i]=p[i].x;
            else if(p[i].x==L) s[i]=L+p[i].y;
            else if(p[i].y==L) s[i]=L*3-p[i].x;
            else s[i]=L*4-p[i].y;
            s[i+n]=s[i]+L*4;
        }
        int l=0,r=L,best=-1;
        while(l&lt;=r)
        {
            int mid=(l+r)&gt;&gt;1;
            if(check(mid))
            {
                best=mid;
                l=mid+1;
            }
            else r=mid-1;
        }
        cout&lt;&lt;best&lt;&lt;endl;
    }
}
